-- Table structure for countries
CREATE TABLE IF NOT EXISTS countries (
    iso VARCHAR(2) PRIMARY KEY,
    name VARCHAR(100) NOT NULL,
    dialCode VARCHAR(5) NOT NULL,
    flag VARCHAR(10) NOT NULL,
    continent VARCHAR(50) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Insert countries

-- Table structure for operators
CREATE TABLE IF NOT EXISTS operators (
    id VARCHAR(50) PRIMARY KEY,
    name VARCHAR(100) NOT NULL,
    brand VARCHAR(50) NOT NULL,
    country VARCHAR(2) NOT NULL,
    logo VARCHAR(255) NOT NULL,
    color VARCHAR(20) NOT NULL,
    FOREIGN KEY (country) REFERENCES countries(iso) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Insert operators

-- Table structure for prefixes
CREATE TABLE IF NOT EXISTS prefixes (
    dialCode VARCHAR(5) NOT NULL,
    prefix VARCHAR(10) NOT NULL,
    operatorId VARCHAR(50) NOT NULL,
    PRIMARY KEY (dialCode, prefix, operatorId),
    INDEX idx_operatorId (operatorId),
    FOREIGN KEY (operatorId) REFERENCES operators(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

